/**
 * Native translations for DA / DE / ET / PL — the four "long-tail" languages
 * we support on top of FI / EN / SV. Kept separate from `translations.ts` to
 * avoid blowing past the 1000-line mark in a single file. The main module
 * spreads this object into `translations` so consumers don't notice.
 *
 * Language list mirrors `SUPPORTED_LANGS` in `translations.ts`. Strings here
 * are hand-translated (not auto-generated) so brand voice and idiom land
 * naturally; review with a native speaker before any further marketing push.
 */
import type { Lang } from "./translations";

// We reuse the Dict shape from translations.ts via type-only re-export to
// keep this file lean. Dict is non-exported there, so we replicate via
// `unknown` + structural typing — hand-checked against the FI dict.
// Any drift causes a TS error in translations.ts when we spread.
type AnyDict = Record<string, unknown>;

